class Solution:
    def minJumps(self, nums):
        from collections import deque
        n = len(nums)
        if n == 1:
            return 0
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        # brute adjacency built explicitly
        from collections import defaultdict
        multiples = defaultdict(list)
        for idx, v in enumerate(nums):
            x = v
            d = 2
            primes = set()
            while d * d <= x:
                while x % d == 0:
                    primes.add(d); x //= d
                d += 1
            if x > 1:
                primes.add(x)
            for p in primes:
                multiples[p].append(idx)
        dist = [-1] * n
        dist[0] = 0
        dq = deque([0])
        used_prime = set()
        while dq:
            i = dq.popleft()
            if i == n - 1:
                return dist[i]
            nbrs = []
            if i - 1 >= 0:
                nbrs.append(i - 1)
            if i + 1 < n:
                nbrs.append(i + 1)
            if is_prime(nums[i]) and nums[i] not in used_prime:
                used_prime.add(nums[i])
                nbrs.extend(multiples[nums[i]])
            for j in nbrs:
                if dist[j] == -1:
                    dist[j] = dist[i] + 1
                    dq.append(j)
        return dist[n - 1]

