class Solution:
    def minJumps(self, nums):
        from collections import deque, defaultdict
        n = len(nums)
        if n == 1:
            return 0
        mx = max(nums)
        spf = list(range(mx + 1))
        i = 2
        while i * i <= mx:
            if spf[i] == i:
                for j in range(i * i, mx + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        def factors(x):
            ps = set()
            while x > 1:
                p = spf[x]
                ps.add(p)
                while x % p == 0:
                    x //= p
            return ps
        buckets = defaultdict(list)
        for idx, v in enumerate(nums):
            for p in factors(v):
                buckets[p].append(idx)
        def is_prime(x):
            return x >= 2 and spf[x] == x
        dist = [-1] * n
        dist[0] = 0
        dq = deque([0])
        while dq:
            i = dq.popleft()
            if i == n - 1:
                return dist[i]
            d = dist[i]
            for j in (i - 1, i + 1):
                if 0 <= j < n and dist[j] == -1:
                    dist[j] = d + 1
                    dq.append(j)
            v = nums[i]
            if is_prime(v) and v in buckets:
                for j in buckets[v]:
                    if dist[j] == -1:
                        dist[j] = d + 1
                        dq.append(j)
                del buckets[v]
        return dist[n - 1]

