var minJumps = function(nums) {
    const n = nums.length;
    if (n === 1) return 0;
    let mx = 0;
    for (const v of nums) if (v > mx) mx = v;
    const spf = new Int32Array(mx + 1);
    for (let i = 0; i <= mx; i++) spf[i] = i;
    for (let i = 2; i * i <= mx; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= mx; j += i) if (spf[j] === j) spf[j] = i;
        }
    }
    const factors = (x) => {
        const ps = [];
        while (x > 1) {
            const p = spf[x];
            ps.push(p);
            while (x % p === 0) x = Math.floor(x / p);
        }
        return ps;
    };
    const buckets = new Map();
    for (let idx = 0; idx < n; idx++) {
        for (const p of factors(nums[idx])) {
            if (!buckets.has(p)) buckets.set(p, []);
            buckets.get(p).push(idx);
        }
    }
    const isPrime = (x) => x >= 2 && spf[x] === x;
    const dist = new Int32Array(n).fill(-1);
    dist[0] = 0;
    const queue = [0];
    let qh = 0;
    while (qh < queue.length) {
        const i = queue[qh++];
        if (i === n - 1) return dist[i];
        const d = dist[i];
        for (const j of [i - 1, i + 1]) {
            if (j >= 0 && j < n && dist[j] === -1) { dist[j] = d + 1; queue.push(j); }
        }
        const v = nums[i];
        if (isPrime(v) && buckets.has(v)) {
            for (const j of buckets.get(v)) {
                if (dist[j] === -1) { dist[j] = d + 1; queue.push(j); }
            }
            buckets.delete(v);
        }
    }
    return dist[n - 1];
};
